frappe.ui.form.on('Report Card Generator', {
	refresh: function(frm) {
		frm.page.set_primary_action(__('Generate Report Cards'), function() {
			generate_report_cards(frm);
		});
	},

	generate_btn: function(frm) {
		generate_report_cards(frm);
	},

	generation_mode: function(frm) {
		frm.refresh_fields();
	}
});

function generate_report_cards(frm) {
	if (!frm.doc.academic_year) {
		frappe.msgprint(__('Please select an Academic Year'));
		return;
	}

	if (frm.doc.generation_mode === 'Single Student' && !frm.doc.student) {
		frappe.msgprint(__('Please select a Student'));
		return;
	}

	if (frm.doc.generation_mode === 'Student Group' && !frm.doc.student_group) {
		frappe.msgprint(__('Please select a Student Group'));
		return;
	}

	let action_text = frm.doc.result_action === 'Save as Draft' ? 'save as drafts' : 'calculate and submit';
	let message = `Generate Report Cards for ${frm.doc.academic_year}`;
	if (frm.doc.generation_mode === 'Single Student' && frm.doc.student) {
		message += ` - ${frm.doc.student}`;
	} else if (frm.doc.generation_mode === 'Student Group' && frm.doc.student_group) {
		message += ` (${frm.doc.student_group})`;
	} else {
		message += ' (All Students)';
	}
	message += ` and ${action_text}?`;

	frappe.confirm(
		message,
		function() {
			frappe.show_alert({
				message: __('Starting generation...'),
				indicator: 'blue'
			});

			frappe.call({
				method: 'education.education.api.generate_report_cards',
				args: {
					generation_mode: frm.doc.generation_mode,
					academic_year: frm.doc.academic_year,
					student: frm.doc.student,
					student_group: frm.doc.student_group,
					result_action: frm.doc.result_action
				},
				callback: function(r) {
					if (r.message && r.message.status === 'success') {
						frappe.show_alert({
							message: r.message.message,
							indicator: 'green'
						});
					} else if (r.message && r.message.status === 'error') {
						frappe.show_alert({
							message: r.message.message,
							indicator: 'red'
						});
					}
				},
				error: function(r) {
					frappe.show_alert({
						message: __('Generation failed. Please check the error log.'),
						indicator: 'red'
					});
				}
			});
		}
	);
}
